#include <vector>
#include <cstdint>

class FenwickTree {
    std::vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size), tree(size + 1, 0) {}
    void update(int index, long long delta) {
        index += 1; // 1-based
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        index += 1; // 1-based
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

